const src = $input.all()[0];
// ── Loop prevention guard ────────────────────────────────────────────────────
const _incomingBody = (src.json && src.json.body) ? src.json.body : {};
const _attemptCount = (_incomingBody.attempt_count !== undefined)
    ? parseInt(_incomingBody.attempt_count, 10) || 0 : 0;
if (_attemptCount >= 1) {
    return [{ json: { loop_detected: true, original_task: _incomingBody,
        bot_name: 'chief_of_staff',
        task: 'loop_escalation', user_text: null, chat_id: null, from_agent: 'loop_guard',
        now_iso: new Date().toISOString(), daily_spec: [], weekly_spec: [] } }];
}
// ── End loop prevention ──────────────────────────────────────────────────────

// ── Deduplication guard ─────────────────────────────────────────────────────
const messageId = (src.json && src.json.message && src.json.message.message_id)
    ? String(src.json.message.message_id)
    : null;


// Detect trigger source by inspecting the item shape.
let task = 'scheduled_tick';
let user_text = null;
let chat_id = null;
let from_agent = 'system';

if (src.json && src.json.message && src.json.message.chat) {
    // Telegram trigger
    task = 'user_dm';
    let _utext = src.json.message.text || '';
    // Strip leading slash from Telegram commands so Super Agent does not classify them as shell commands.
    if (_utext.startsWith('/')) {
        const parts = _utext.slice(1).split(/\s+/);
        const cmd = (parts[0] || '').toLowerCase();
        const rest = parts.slice(1).join(' ');
        if (cmd === 'start' || cmd === 'help') { _utext = 'Hello - please introduce yourself, your role in Bridge Digital, and what you can help with right now.'; }
        else if (cmd === 'status') { _utext = 'Give me a brief status update on your current focus and any open items in your inbox.'; }
        else { _utext = (cmd + ' ' + rest).trim(); }
    }
    user_text = _utext;
    chat_id = src.json.message.chat.id;
    from_agent = 'user';
} else if (src.json && src.json.body && src.json.body.task) {
    // Webhook trigger
    task = src.json.body.task;
    user_text = src.json.body.message || null;
    from_agent = src.json.body.from_agent || 'system';
    chat_id = null; // webhooks do not carry a telegram chat
} else if (src.json && src.json.timestamp) {
    // Schedule trigger
    task = 'scheduled_tick';
    user_text = null;
    from_agent = 'system';
}

return [{ json: { message_id: messageId,
    bot_name: "chief_of_staff",
    task,
    user_text,
    chat_id,
    from_agent,
    now_iso: new Date().toISOString(),
    daily_spec: [{"hour": 8, "minute": 0, "task_name": "day_open_alignment"}, {"hour": 12, "minute": 30, "task_name": "midday_blocker_review"}, {"hour": 20, "minute": 0, "task_name": "day_close_reconciliation"}],
    weekly_spec: [{"weekday": 4, "hour": 10, "minute": 0, "task_name": "weekly_profit_review"}, {"weekday": 5, "hour": 18, "minute": 0, "task_name": "weekly_strategic_summary"}],
} }];

const _buildTask = $('Build task payload').first().json;
if (_buildTask.loop_detected) {
    return [{ json: {
        message: JSON.stringify({ reply_text: '', actions: [{ type: 'no_op', payload: {
            reason: 'loop_detected', attempt_count: (_buildTask.original_task && _buildTask.original_task.attempt_count) || 1
        }}]}),
        session_id: 'bridge-loop-guard-' + Date.now(),
        task_kind: 'loop_escalation', user_chat_id: null,
        bot_name: _buildTask.bot_name || 'unknown', _pre_formed: true
    }}];
}

const task = $('Build task payload').first().json;
const inboxRow = $('Fetch open inbox').first().json || {};
const inbox = Array.isArray(inboxRow.open_inbox) ? inboxRow.open_inbox : [];
const ctxRow = $('Fetch bot context').first().json || {};
const ctx = ctxRow.context ? [ctxRow.context] : [ctxRow];


const globalProtocol = `

GLOBAL OPERATING PROTOCOL (non-negotiable):
1. ALWAYS respond in valid JSON only. No prose, no markdown outside JSON strings.
2. EXACT response structure: {"reply_text": "...", "actions": [...]}
3. reply_text: human-readable Telegram message. Brief, role-appropriate.
4. actions: array of {type, payload} objects. Empty array if no actions.
5. NEVER include PLACEHOLDER, PASTE_, TBD, INSERT_HERE values in any field.
6. NEVER mention internal tools (n8n, shell, SQL, workflow IDs) in reply_text.
7. If required data is missing → return no_op with status "need_input" + list exact missing fields.
8. If blocked → escalate to Chief of Staff. NEVER retry autonomously.
9. MAX_RETRIES = 1. If attempt_count >= 1 in incoming body_json → return no_op immediately.
`;

const system = "You are Bridge_Chief_Of_Staff_bot, the executive orchestration and cross-functional coordination super-agent inside Bridge Digital Solutions.\n\nROLE\nYou are the central execution coordinator for the enterprise. You translate strategy into action, keep departments aligned, track dependencies, surface blockers, enforce follow-through, and maintain operational rhythm across the multi-agent ecosystem.\n\nPRIMARY OBJECTIVES\n1. Turn executive goals into coordinated action.\n2. Keep all super-agents aligned to priorities, deadlines, and dependencies.\n3. Prevent drift, duplication, delay, and confusion.\n4. Maintain operational accountability across the organization.\n5. Make sure the right information reaches the right agent at the right time.\n\nSECONDARY OBJECTIVES\n1. Summarize state across the business for leadership.\n2. Escalate blockers, risks, and missed deadlines early.\n3. Improve execution speed, coordination quality, and clarity.\n4. Support budget-aware prioritization with leadership and finance.\n\nCORE FUNCTIONS\n1. Cross-agent coordination\n2. Task routing and follow-up\n3. Priority tracking\n4. Dependency management\n5. Meeting orchestration\n6. Decision logging\n7. Action-item enforcement\n8. Executive summarization\n9. Escalation handling\n10. Operational rhythm management\n\nWHAT YOU MUST DO\n- maintain visibility over all major initiatives\n- know which agent owns which task\n- know what is blocked, overdue, or waiting for input\n- push unresolved items toward a decision\n- ensure inter-agent communication happens in correct sequence\n- request status updates when needed\n- summarize complex situations for leadership\n- coordinate daily and weekly operating cadence\n\nDECISION PRINCIPLES\n- Optimize for clarity, speed, alignment, and execution.\n- Do not allow silent drift.\n- Convert vague goals into concrete next actions.\n- Keep teams focused on high-priority and high-impact outcomes.\n- Escalate early, not late.\n- Prefer decisive coordination over passive observation.\n\nAUTHORITY AND AUTONOMY\nYou may: request updates from any agent, consolidate reports, schedule check-ins and review cycles, re-surface unresolved issues, recommend reprioritization, escalate blockers to the CEO.\nYou may not: override core security decisions, override final strategic decisions from the CEO, override hard budget constraints from finance \u2014 unless explicitly delegated.\n\nINTERACTION RULES\nYou work closely with Bridge_CEO_BOT for strategic direction, Bridge_Researcher_bot for intelligence intake, Bridge_Chief_Sec_Off_bot for risk visibility, operational/financial agents for project movement, and Bridge_Cleaner_bot for cleanup cycles.\n\n

INTENT ROUTING — YOU ARE THE MANDATORY GATEWAY
Every inter-agent request MUST flow through you first. Never let a message bypass this routing:

| Intent keywords                          | Route to               |
|------------------------------------------|------------------------|
| approve, authorise, authorize, sign off, greenlight | CEO → then back to requester |
| budget, spend, cost, invoice, payment    | Finance (after COS review) |
| build website, design page, landing page | PM → Website Bot       |
| security risk, vulnerability, threat     | Chief Sec Off          |
| research, investigate, market analysis   | Researcher Bot         |
| code, develop, implement, fix bug        | Programmer Bot         |
| deploy, redeploy, restart service        | Self-Improve / Shell Agent via super-agent |
| cleanup, archive, delete old             | Cleaner Bot            |

RULE: If you receive a message that belongs to a different agent, DO NOT forward it silently.
Acknowledge receipt, state which agent will handle it, and MEMO that agent via the action system.
This prevents messages going to the wrong bot (e.g. 'Approve project' must NEVER go to Finance directly).

ESCALATE WHEN priorities conflict, multiple agents are blocked, deadlines slip, budgets constrain execution, risk rises materially, decisions are pending too long, or coordination failure is likely.\n\nOUTPUT STYLE\nUse concise executive language. Always organize outputs as: current state, blockers, required decisions, next actions, owners, deadlines.\n\nSUCCESS DEFINITION\nYou are successful when the company stays aligned, blockers are resolved early, and important work moves reliably from strategy to execution.\n
ORCHESTRATION AUTHORITY:
When you receive a memo with memo_type='execution_approved' from CEO:
1. Read approved_to_agent field
2. Issue memo to that agent with memo_type='execution_directive', body containing original body_json + status='approved_to_proceed' + attempt_count=0
3. Log handoff in workflow_events memo

LOOP ESCALATION HANDLING:
When you receive a memo with reason='loop_detected':
1. Archive the loop memo
2. Reply to human (reply_text) describing which task looped
3. Recommend manual intervention — do NOT re-dispatch";

const contextBlock = JSON.stringify({
    now: task.now_iso,
    bot: task.bot_name,
    task_kind: task.task,
    open_inbox: inbox,
    bot_context: ctx,
    daily_cadence: task.daily_spec,
    weekly_cadence: task.weekly_spec,
}, null, 2);

const taskBlock = task.task === 'user_dm'
    ? `The user sent you this message on Telegram:\n${task.user_text}\n\nRespond helpfully and consider issuing actions if appropriate.`
    : task.task === 'scheduled_tick'
      ? `This is a scheduled cadence run. Decide what to do given the current context, open memos, and your role.`
      : `An inter-agent invocation arrived from '${task.from_agent}': ${task.user_text || 'no message body'}. Decide how to respond.`;

const outputGuard = `\n\n[OUTPUT FORMAT]\nReturn ONLY a JSON object (no prose, no markdown fences):\n{\n  "reply_text": "<what to send back via Telegram; empty string when a scheduled run should stay silent>",\n  "actions": [\n    {"type": "memo",     "payload": {"to_agent": "researcher|chief_of_staff|cso|ceo|cleaner|all", "memo_type": "status|proposal|directive|question|decision", "priority": "urgent|high|normal|low", "subject": "...", "body_json": {...}}},\n    {"type": "archive",  "payload": {"memo_id": "<uuid-from-open-inbox>", "reason": "..."}},\n    {"type": "query",    "payload": {"sql": "<safe single SELECT>"}},\n    {"type": "escalate", "payload": {"subject": "...", "body_json": {...}}},\n    {"type": "cleanup",  "payload": {"slug": "...", "reason": "..."}},\n    {"type": "no_op",    "payload": {"reason": "..."}}\n  ]\n}\nKeep actions <= 5. Never include non-whitelisted action types. User-facing commentary belongs in reply_text, not in alert actions.`;

const fullMessage = `${system}${globalProtocol}\n\n[CONTEXT]\n${contextBlock}\n\n[TASK]\n${taskBlock}${outputGuard}`;

return [{ json: {
    message: fullMessage,
    session_id: `bridge-${task.bot_name}-${task.now_iso.slice(0,16).replace(/[:T-]/g,'')}`,
    task_kind: task.task,
    user_chat_id: task.chat_id,
    bot_name: task.bot_name,
} }];

// ── Pre-formed short-circuit (loop guard) ──────────────────────────────────
const _upstream = $('Assemble prompt').first().json;
if (_upstream && _upstream._pre_formed) {
    let _pfActions;
    try { _pfActions = JSON.parse(_upstream.message).actions; } catch(e) { _pfActions = []; }
    return [{ json: {
        reply_text: '',
        actions: [{ type: 'no_op', risk: 'low',
            payload: (_pfActions[0] && _pfActions[0].payload) || { reason: 'loop_guard' } }],
        bot_name: _upstream.bot_name, user_chat_id: _upstream.user_chat_id,
        task_kind: 'loop_escalation', model_used: 'loop_guard', parse_error: null
    }}];
}

// ── Standard parse + risk + validation ─────────────────────────────────────
const raw = $json.response || '';
const riskMap = { "memo": "low", "archive": "low", "no_op": "low",
                  "escalate": "low", "query": "medium", "cleanup": "high" };
const defaultRisk = 'low';

let parsed = null, parseError = null;
try {
    let cleaned = raw.trim().replace(/^```(?:json)?/, '').replace(/```$/, '').trim();
    parsed = JSON.parse(cleaned);
} catch (e) { parseError = e.message; }
if (!parsed) {
    try { const m = raw.match(/\{[\s\S]*\}/); if (m) parsed = JSON.parse(m[0]); } catch (e) {}
}

let reply_text = '', actions = [];
if (parsed && typeof parsed === 'object' && parsed.reply_text !== undefined) {
    reply_text = typeof parsed.reply_text === 'string' ? parsed.reply_text : '';
    actions = Array.isArray(parsed.actions) ? parsed.actions.slice(0, 5) : [];
} else {
    reply_text = '';
    actions = [{ type: 'no_op', payload: {
        reason: 'json_parse_failed',
        parse_error: parseError || 'no structured response from model',
        raw_preview: String(raw).slice(0, 200)
    }}];
}

// ── Placeholder validation ──────────────────────────────────────────────────
const BANNED = ['PASTE_', 'TBD', 'PLACEHOLDER', 'INSERT_HERE', 'YOUR_URL'];
const hasPlaceholder = (str) => BANNED.some(p => String(str).includes(p));
if (hasPlaceholder(reply_text) || actions.some(a => hasPlaceholder(JSON.stringify(a)))) {
    reply_text = '[Output validation failed — response contained placeholder values. Please provide the actual value.]';
    actions = [{ type: 'no_op', payload: { reason: 'placeholder_detected' }}];
}

// ── Internal tool leakage scrubbing (non-blocking) ─────────────────────────
const leakageMap = {
    'n8n workflow creation': 'automation system modification',
    'n8n workflow modification': 'automation system modification',
    'shell command (destructive)': 'system operation',
    'shell command': 'system operation',
    'SQL query': 'data operation',
};
for (const [internal, safe] of Object.entries(leakageMap)) {
    if (reply_text.toLowerCase().includes(internal.toLowerCase()))
        reply_text = reply_text.replace(new RegExp(internal, 'gi'), safe);
}

// ── Risk annotation ─────────────────────────────────────────────────────────
const annotated = actions.map(a => {
    const type = (a && typeof a.type === 'string') ? a.type : 'no_op';
    let risk = riskMap[type] !== undefined ? riskMap[type] : defaultRisk;
    return { type, risk, payload: a.payload || {} };
});

const upstream = $('Assemble prompt').first().json;
return [{ json: {
    reply_text, actions: annotated,
    bot_name: upstream.bot_name, user_chat_id: upstream.user_chat_id,
    task_kind: upstream.task_kind, model_used: $json.model_used || 'unknown',
    parse_error: parseError
}}];

const p = $json;
const out = [];
for (const a of (p.actions || [])) {
    out.push({ json: {
        action_type: a.type,
        action_risk: a.risk,
        action_payload: a.payload,
        bot_name: p.bot_name,
        user_chat_id: p.user_chat_id,
        task_kind: p.task_kind,
        model_used: p.model_used,
        reply_text: p.reply_text,
    }});
}
// Always emit at least one item so the reply path runs even when no actions.
if (out.length === 0) {
    out.push({ json: {
        action_type: 'no_op',
        action_risk: 'low',
        action_payload: { reason: 'no actions from LLM' },
        bot_name: p.bot_name,
        user_chat_id: p.user_chat_id,
        task_kind: p.task_kind,
        model_used: p.model_used,
        reply_text: p.reply_text,
    }});
}
return out;

